// Assemble comprehensive context per user for Claude briefing
const stagingData = $('Read All Staging Data').all().map(i => i.json);
const users = $('Get Users & Holdings').all().map(i => i.json);
const allAlerts = $('Get Active Alerts').all().map(i => i.json);

// Organize staging data by type
const staged = {};
for (const row of stagingData) {
  const data = typeof row.data === 'string' ? JSON.parse(row.data) : row.data;
  if (row.symbol) {
    if (!staged[row.data_type]) staged[row.data_type] = {};
    staged[row.data_type][row.symbol] = data;
  } else {
    staged[row.data_type] = data;
  }
}

// Generate personalized briefing request per user
const briefingRequests = [];

for (const user of users) {
  const userAlerts = allAlerts.filter(a => a.user_id === user.user_id);
  const holdings = user.holdings || [];

  // Build per-stock technical data
  const stockAnalysis = [];
  for (const h of holdings) {
    if (!h.symbol) continue;
    const tech = staged.technicals?.[h.symbol] || null;
    const sentiment = (staged.options_news?.news_sentiment || [])
      .find(s => s.symbol === h.symbol);
    const alert = userAlerts.find(a => a.symbol === h.symbol);

    stockAnalysis.push({
      symbol: h.symbol,
      quantity: h.qty,
      avg_buy_price: h.avg_price,
      invested: h.invested,
      technicals: tech,
      sentiment: sentiment || null,
      alert: alert || null
    });
  }

  const context = {
    user_name: user.display_name,
    global_cues: staged.global_cues || {},
    fii_dii: staged.fii_dii || {},
    nifty_options: staged.options_news?.nifty_options || {},
    corporate_actions: staged.options_news?.corporate_actions || {},
    news_headlines: staged.options_news?.news_articles || [],
    stock_analysis: stockAnalysis,
    active_alerts_count: userAlerts.length
  };

  briefingRequests.push({
    user_id: user.user_id,
    chat_id: user.alerts_chat_id || user.private_chat_id,
    display_name: user.display_name,
    context: context
  });
}

return briefingRequests.map(r => ({ json: r }));

// Handle errors from Claude API
const resp = $input.first().json;
let text = '';
try {
  if (resp.content && resp.content[0]) {
    text = resp.content[0].text;
  } else {
    text = 'Morning briefing generation failed. Your portfolio data is being monitored and alerts are active.';
  }
} catch(e) {
  text = 'Morning briefing generation failed. Your portfolio data is being monitored and alerts are active.';
}

// Sanitize Telegram markdown
try {
  text = text.replace(/```\w+/g, '```');
  const starCount = (text.match(/\*/g) || []).length;
  if (starCount % 2 !== 0) {
    const lastIdx = text.lastIndexOf('*');
    text = text.substring(0, lastIdx) + text.substring(lastIdx + 1);
  }
} catch(e2) {
  text = text.replace(/[*_`\[\]]/g, '');
}

// Get user info from Assemble context
const ctx = $('Assemble Per-User Context').first().json;
return [{
  json: {
    chat_id: ctx.chat_id || ctx.private_chat_id,
    message: text,
    reply_markup: JSON.stringify({
      inline_keyboard: [
        [{text: "Portfolio", callback_data: "portfolio"}, {text: "My Alerts", callback_data: "alerts"}],
        [{text: "Help", callback_data: "help"}]
      ]
    })
  }
}];

